export function findLongitude(
  provinceName: string, cityName: string, districtName: string,
): number | undefined {
  const province = PROVINCES.find(p => p.name === provinceName);
  const city = province?.cities.find(ct => ct.name === cityName);
  const district = city?.districts.find(d => d.name === districtName);
  return district?.longitude;
}

export function getCityByName(name: string): { name: string; province: string; longitude: number } | undefined {
  for (const p of PROVINCES) {
    for (const ct of p.cities) {
      if (ct.name === name) {
        return { name: ct.name, province: p.name, longitude: ct.districts[0].longitude };
      }
    }
  }
  return undefined;
}

/* ── 自动生成的扁平列表与辅助函数 ─────────────────────── */

/** 所有省份名称 */
export const ALL_PROVINCE_NAMES: string[] = PROVINCES.map(p => p.name);

/** 所有城市名（去重） */
export const ALL_CITY_NAMES: string[] = [...new Set(PROVINCES.flatMap(p => p.cities.map(c => c.name)))];

/** 所有区县名（去重） */
export const ALL_DISTRICT_NAMES: string[] = [...new Set(PROVINCES.flatMap(p => p.cities.flatMap(c => c.districts.map(d => d.name))))];

/** 扁平化城市经度列表（兼容旧接口） */
export const CITY_LNG: [string, number][] = PROVINCES.flatMap(p =>
  p.cities.map(ct => [ct.name, ct.districts[0].longitude] as [string, number])
);

/** 获取某省的所有城市名 */
export function getCityNamesOfProvince(provinceName: string): string[] {
  return PROVINCES.find(p => p.name === provinceName)?.cities.map(c => c.name) ?? [];
}

/** 获取某省某市的所有区县名 */
export function getDistrictNamesOfCity(provinceName: string, cityName: string): string[] {
  const prov = PROVINCES.find(p => p.name === provinceName);
  return prov?.cities.find(c => c.name === cityName)?.districts.map(d => d.name) ?? [];
}

/** 通过省/市/区三级名称查经度 */
export function getLongitude(provinceName: string, cityName: string, districtName: string): number | undefined {
  const prov = PROVINCES.find(p => p.name === provinceName);
  const city = prov?.cities.find(c => c.name === cityName);
  const dist = city?.districts.find(d => d.name === districtName);
  return dist?.longitude;
}

/** 真太阳时校正：真太阳时 ≈ 北京时间 + (经度 - 120) × 4 分钟 */
export function applyTrueSolarTime(hour: number, minute: number, longitude: number): { hour: number; minute: number; offsetMin: number } {
  const offsetMin = Math.round((longitude - 120) * 4);
  let totalMin = hour * 60 + minute + offsetMin;
  totalMin = ((totalMin % 1440) + 1440) % 1440;
  return { hour: Math.floor(totalMin / 60), minute: totalMin % 60, offsetMin };
}

/** 根据小时+分钟判断时辰索引（iztro 0~12） */
export function hourToBirthTimeIndex(h: number, m: number): number {
  if (h === 23) return 12;  // 23:00~23:59 = 晚子时
  if (h === 0) return 0;    // 00:00~00:59 = 早子时
  return Math.floor((h + 1) / 2);
}